 * Function: Test transactional observer updates
 *
 * @param nodeName Name for the node to update
 * @return bool Whether transactional update succeeded (no cycle created)
 */
bool test_transactional_update(const std::string& nodeName) {
    // 1. Create observer nodes
    auto node1 = std::make_shared<TestTransactionalObserver>(nodeName);
    auto node2 = std::make_shared<TestTransactionalObserver>("DependentNode");

    // 2. Get observer graph instance
    auto graph = reaction::ObserverGraph::getInstance();

    // 3. Set up initial relationship: node1 observes node2
    graph.addObserver(node2, node1);

    // 4. Notify target and verify relationship works
    node2->reset();
    node1->reset();
    node2->valueChanged(true); // Trigger change on node2

    // Verify node1 was notified
    if (!node1->wasChanged()) {
        return false; // Initial relationship failed
    }

    // 5. Reset observer for next test
    node1->reset();
    node2->reset();

    bool cycleDetected = false;

    try {
        // 6. Attempt transactional update that would create cycle
        // Update node1's observers to include node2 (existing relationship)
        graph.updateObserversTransactional(node1, {node2});

        // Now try to create a cycle: node2 observes node1
        graph.updateObserversTransactional(node2, {node1});
    }
    catch (const reaction::DependencyCycleException& e) {
        // 7. Catch cycle exception if thrown
        cycleDetected = true;
    }

    if (!cycleDetected) {
        return false; // Expected cycle exception was not thrown
    }

    // 8. Notify target again after cycle attempt
    node2->valueChanged(true);

    // 9. Verify original relationship is preserved
    // Check if node1 was notified again (relationship still works)
    if (!node1->wasChanged()) {
        return false; // Original relationship broken
    }

    // Additional verification: check if the cycle was not created
    // by attempting to notify in the opposite direction
    node1->reset();
    node2->valueChanged(true); // Should still work

    if (!node1->wasChanged()) {
        return false; // Cycle creation affected existing relationship
    }

    // 10. Return success status
    return true;
}

