```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

struct BatchLifecycleResult {
    bool closedInitially;
    bool closedAfterClose;
    int recomputeCountAfterExecute;
};

BatchLifecycleResult test_batch_manual_lifecycle(int initialValue, int updatedValue) {
    // 1. Create reactive variable using reaction::var with initialValue
    auto reactiveVar = reaction::var(initialValue);

    // 2. Create counter variable to track recomputation count
    int recomputeCounter = 0;

    // 3. Create calculation using reaction::calc that depends on reactive variable
    // The calculation increments the counter each time it runs
    auto calcResult = reaction::calc([&]() -> int {
        // Access the reactive variable to establish dependency
        int currentValue = reactiveVar();
        // Increment counter when this calculation runs
        recomputeCounter++;
        return currentValue;
    });

    // 4. Create Batch object using reaction::batch with lambda that updates reactive variable
    auto batchObj = reaction::batch([&]() {
        // Update the reactive variable within the batch
        reactiveVar.value(updatedValue);
    });

    // 5. Check if batch is closed initially using isClosed() method
    bool closedInitially = batchObj.isClosed();

    // 6. Execute batch using execute() method
    batchObj.execute();

    // 7. Record recompute count after execute
    int recomputeCountAfterExecute = recomputeCounter;

    // 8. Close batch using close() method
    batchObj.close();

    // 9. Check if batch is closed after close using isClosed() method
    bool closedAfterClose = batchObj.isClosed();

    // 10. Ensure calculation is evaluated by accessing its value
    // This will trigger any pending recomputation
    int finalCalcValue = calcResult();

    // 11. Return BatchLifecycleResult struct with collected data
    return BatchLifecycleResult{
        .closedInitially = closedInitially,
        .closedAfterClose = closedAfterClose,
        .recomputeCountAfterExecute = recomputeCountAfterExecute
    };
}

}  // namespace test_reaction
```

