#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

struct ValiditySnapshot {
    bool firstValidBeforeClose;
    bool firstValidAfterClose;
    bool copiesEqualBeforeClose;
    bool copiesEqualAfterClose;
    bool equalityCheckFailedAfterClose;
};

/**
 * Function: Demonstrate React::operator bool and operator== for validity tracking.
 *
 * @param initialValue Initial value stored inside the reactive variable
 * @return ValiditySnapshot Snapshot describing validity/equality before and after close
 */
inline ValiditySnapshot test_react_validity(int initialValue) {
    ValiditySnapshot snapshot{};

    // 1. Create reactive variable using reaction::var with initialValue
    auto first = reaction::var(initialValue);

    // 2. Create copy of the reactive variable
    auto second = first;

    // 3. Check validity of both copies before close using operator bool
    snapshot.firstValidBeforeClose = static_cast<bool>(first);
    bool secondValidBeforeClose = static_cast<bool>(second);

    // 4. Check equality of both copies before close using operator==
    snapshot.copiesEqualBeforeClose = (first == second);

    // 5. Close the source node using close() method
    first.close();

    // 6. Check validity of both copies after close
    snapshot.firstValidAfterClose = static_cast<bool>(first);
    bool secondValidAfterClose = static_cast<bool>(second);

    // 7. Check equality of both copies after close with exception handling
    snapshot.equalityCheckFailedAfterClose = false;
    snapshot.copiesEqualAfterClose = false;

    try {
        // Attempt to check equality after close
        snapshot.copiesEqualAfterClose = (first == second);
    } catch (...) {
        // Handle potential exceptions during equality check after close
        snapshot.equalityCheckFailedAfterClose = true;
        snapshot.copiesEqualAfterClose = false;
    }

    // 8. Return validity snapshot
    return snapshot;
}

}  // namespace test_reaction
