    int32_t m_value;
    bool m_lastReportedChange;
};

/**
 * Function: test_atomic_compound_helpers
 *
 * Demonstrates the low-level atomic compound helper APIs:
 * - atomicCompoundAssign
 * - atomicAddAssign
 * - atomicMultiplyAssign
 * - atomicBitwiseAndAssign
 * - atomicLeftShiftAssign
 * - atomicIncrement
 *
 * These helpers operate on a simple IntAtomicImpl type instead of a full
 * React wrapper, making it easy to observe value and change reporting.
 *
 * @param initial Initial integer value
 * @return AtomicHelperSnapshot
 *         Snapshot containing the final value and which operations reported
 *         that a change occurred.
 */
inline AtomicHelperSnapshot test_atomic_compound_helpers(int32_t initial) {
    IntAtomicImpl atomicInt(initial);
    AtomicHelperSnapshot snapshot{};

    // Apply atomic add assignment and record change status
    reaction::atomicAddAssign(atomicInt, 5);
    snapshot.addReportedChange = atomicInt.lastReportedChange();

    // Apply atomic multiply assignment and record change status  
    reaction::atomicMultiplyAssign(atomicInt, 2);
    snapshot.multiplyReportedChange = atomicInt.lastReportedChange();

    // Apply atomic bitwise AND assignment and record change status
    reaction::atomicBitwiseAndAssign(atomicInt, 0xF);
    snapshot.andReportedChange = atomicInt.lastReportedChange();

    // Apply atomic left shift assignment and record change status
    reaction::atomicLeftShiftAssign(atomicInt, 3);
    snapshot.leftShiftReportedChange = atomicInt.lastReportedChange();

    // Apply atomic increment and record change status
    reaction::atomicIncrement(atomicInt);
    snapshot.incrementReportedChange = atomicInt.lastReportedChange();

    // Get final value
    snapshot.finalValue = atomicInt.value();

    return snapshot;
}

